import asyncio
import json
import math
import time
import uuid
from dataclasses import dataclass, field, asdict
from typing import Dict, List, Optional, Any, Set

import websockets


TICK_RATE = 20
TICK_INTERVAL = 1.0 / TICK_RATE
WORLD_BOUNDS = 10000.0
MAX_HEALTH = 100
MAX_NAME_LEN = 24
SERVER_HOST = "0.0.0.0"
SERVER_PORT = 8765


def now() -> float:
    return time.time()


def clamp(v: float, lo: float, hi: float) -> float:
    return max(lo, min(hi, v))


def safe_name(name: str) -> str:
    if not isinstance(name, str):
        return "player"
    name = name.strip()
    if not name:
        return "player"
    return name[:MAX_NAME_LEN]


@dataclass
class Vec3:
    x: float
    y: float
    z: float

    def to_dict(self) -> Dict[str, float]:
        return {"x": self.x, "y": self.y, "z": self.z}


@dataclass
class Player:
    id: str
    name: str
    pos: Vec3
    vel: Vec3
    yaw: float = 0.0
    pitch: float = 0.0
    health: int = MAX_HEALTH
    alive: bool = True
    connected: bool = True
    weapon: str = "rifle"
    ammo: int = 30
    team: Optional[str] = None
    last_input_at: float = field(default_factory=now)
    last_seen_at: float = field(default_factory=now)
    kills: int = 0
    armor: int = 0

    def public_state(self) -> Dict[str, Any]:
        return {
            "id": self.id,
            "name": self.name,
            "pos": self.pos.to_dict(),
            "vel": self.vel.to_dict(),
            "yaw": self.yaw,
            "pitch": self.pitch,
            "health": self.health,
            "alive": self.alive,
            "connected": self.connected,
            "weapon": self.weapon,
            "ammo": self.ammo,
            "team": self.team,
            "kills": self.kills,
            "armor": self.armor,
        }


@dataclass
class MatchState:
    phase: str = "lobby"
    started_at: float = field(default_factory=now)
    elapsed: float = 0.0
    zone_center: Vec3 = field(default_factory=lambda: Vec3(0.0, 0.0, 0.0))
    zone_radius: float = 5000.0
    zone_next_radius: float = 4000.0
    players_alive: int = 0
    tick: int = 0

    def to_dict(self) -> Dict[str, Any]:
        return {
            "phase": self.phase,
            "started_at": self.started_at,
            "elapsed": self.elapsed,
            "zone_center": self.zone_center.to_dict(),
            "zone_radius": self.zone_radius,
            "zone_next_radius": self.zone_next_radius,
            "players_alive": self.players_alive,
            "tick": self.tick,
        }


class GameServer:
    def __init__(self) -> None:
        self.clients: Dict[websockets.WebSocketServerProtocol, str] = {}
        self.players: Dict[str, Player] = {}
        self.match = MatchState()
        self.running = True

    async def handler(self, websocket: websockets.WebSocketServerProtocol) -> None:
        player_id = str(uuid.uuid4())
        player = Player(
            id=player_id,
            name=f"player_{player_id[:6]}",
            pos=Vec3(0.0, 0.0, 0.0),
            vel=Vec3(0.0, 0.0, 0.0),
        )
        self.clients[websocket] = player_id
        self.players[player_id] = player
        await self.send(
            websocket,
            {
                "type": "welcome",
                "player_id": player_id,
                "tick_rate": TICK_RATE,
                "world_bounds": WORLD_BOUNDS,
            },
        )
        await self.broadcast_roster()

        try:
            async for raw in websocket:
                await self.handle_message(websocket, raw)
        except websockets.ConnectionClosed:
            pass
        finally:
            await self.disconnect(websocket)

    async def disconnect(self, websocket: websockets.WebSocketServerProtocol) -> None:
        player_id = self.clients.pop(websocket, None)
        if not player_id:
            return
        player = self.players.get(player_id)
        if player:
            player.connected = False
            player.alive = False
            player.last_seen_at = now()
        await self.broadcast_roster()

    async def handle_message(self, websocket: websockets.WebSocketServerProtocol, raw: str) -> None:
        try:
            msg = json.loads(raw)
        except Exception:
            return

        player_id = self.clients.get(websocket)
        if not player_id or player_id not in self.players:
            return
        player = self.players[player_id]
        player.last_seen_at = now()

        msg_type = msg.get("type")
        if msg_type == "join":
            player.name = safe_name(msg.get("name", player.name))
            await self.send(
                websocket,
                {
                    "type": "joined",
                    "player": player.public_state(),
                    "match": self.match.to_dict(),
                },
            )
            await self.broadcast_roster()
        elif msg_type == "input":
            self.apply_input(player, msg)
        elif msg_type == "respawn":
            self.respawn(player)
        elif msg_type == "ping":
            await self.send(websocket, {"type": "pong", "t": msg.get("t", now())})

    def apply_input(self, player: Player, msg: Dict[str, Any]) -> None:
        pos = msg.get("pos")
        vel = msg.get("vel")
        yaw = msg.get("yaw")
        pitch = msg.get("pitch")
        weapon = msg.get("weapon")
        ammo = msg.get("ammo")
        health = msg.get("health")
        armor = msg.get("armor")
        alive = msg.get("alive")

        if isinstance(pos, dict):
            player.pos.x = clamp(float(pos.get("x", player.pos.x)), -WORLD_BOUNDS, WORLD_BOUNDS)
            player.pos.y = clamp(float(pos.get("y", player.pos.y)), -WORLD_BOUNDS, WORLD_BOUNDS)
            player.pos.z = clamp(float(pos.get("z", player.pos.z)), -WORLD_BOUNDS, WORLD_BOUNDS)

        if isinstance(vel, dict):
            player.vel.x = float(vel.get("x", player.vel.x))
            player.vel.y = float(vel.get("y", player.vel.y))
            player.vel.z = float(vel.get("z", player.vel.z))

        if isinstance(yaw, (int, float)):
            player.yaw = float(yaw)
        if isinstance(pitch, (int, float)):
            player.pitch = float(pitch)
        if isinstance(weapon, str):
            player.weapon = weapon[:32]
        if isinstance(ammo, int):
            player.ammo = max(0, ammo)
        if isinstance(health, int):
            player.health = max(0, min(MAX_HEALTH, health))
        if isinstance(armor, int):
            player.armor = max(0, min(100, armor))
        if isinstance(alive, bool):
            player.alive = alive and player.health > 0

        player.last_input_at = now()

    def respawn(self, player: Player) -> None:
        player.pos = Vec3(0.0, 0.0, 0.0)
        player.vel = Vec3(0.0, 0.0, 0.0)
        player.health = MAX_HEALTH
        player.armor = 0
        player.ammo = 30
        player.alive = True
        player.connected = True

    async def send(self, websocket: websockets.WebSocketServerProtocol, payload: Dict[str, Any]) -> None:
        try:
            await websocket.send(json.dumps(payload, separators=(",", ":")))
        except Exception:
            pass

    async def broadcast(self, payload: Dict[str, Any]) -> None:
        if not self.clients:
            return
        data = json.dumps(payload, separators=(",", ":"))
        stale: List[websockets.WebSocketServerProtocol] = []
        for ws in list(self.clients.keys()):
            try:
                await ws.send(data)
            except Exception:
                stale.append(ws)
        for ws in stale:
            await self.disconnect(ws)

    async def broadcast_roster(self) -> None:
        await self.broadcast(
            {
                "type": "roster",
                "players": [p.public_state() for p in self.players.values() if p.connected],
            }
        )

    def update_match(self) -> None:
        self.match.elapsed = now() - self.match.started_at
        self.match.players_alive = sum(1 for p in self.players.values() if p.connected and p.alive)
        self.match.tick += 1
        if self.match.phase == "lobby" and self.match.players_alive >= 2:
            self.match.phase = "active"

    def full_game_state(self) -> Dict[str, Any]:
        return {
            "type": "state",
            "server_time": now(),
            "match": self.match.to_dict(),
            "players": [p.public_state() for p in self.players.values()],
        }

    async def game_loop(self) -> None:
        while self.running:
            started = time.perf_counter()
            self.update_match()
            await self.broadcast(self.full_game_state())
            elapsed = time.perf_counter() - started
            await asyncio.sleep(max(0.0, TICK_INTERVAL - elapsed))


async def main() -> None:
    server = GameServer()
    async with websockets.serve(server.handler, SERVER_HOST, SERVER_PORT, max_size=2**20):
        await server.game_loop()


if __name__ == "__main__":
    asyncio.run(main())